// // This module is designed to decrement a 4-bit counter asynchronously on reset and synchronously on the rising edge of the clock when enabled.
module sync_counter_4bit (
    input clk,
    input reset,
    input enable,
    output reg [3:0] count
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 4'b0000;
        else if (enable)
            count <= count + 1;
    end

endmodule
